checker_dsl:
EXISTS (`data flow source node SRC`, `data flow sink node SNK`, `reference type VERIFIER`) {
  AND {
    (`there exists a data flow path from SRC to SNK`),
    (`SRC is a ClassInstanceExpr`),
    (`VERIFIER is the constructed type of SRC`),
    (`VERIFIER has HostnameVerifier as an ancestor type`),
    EXISTS (`method M`) {
      AND {
        (`M is a HostnameVerifierVerify method`),
        FORALL (`return statement RS`) {
          AND {
            (`RS has a return expression`),
            (`the return expression is a compile-time constant expression`),
            (`the boolean value of the return expression is true`)
          }
        }
      }
    },
    (`SNK is a HostnameVerifierSink node`),
    NOT {
      EXISTS (`guard G`) {
        AND {
          (`G controls the basic block containing SNK's expression`),
          OR {
            (`G is a security feature flag guard`),
            EXISTS (`UnsafeHostnameVerificationFlag flag`) {
              AND {
                (`G is an expression of flag`),
                (`flag name matches regex pattern (?i).*(secure|disable|selfCert|selfSign|validat|verif|trust|ignore|nocertificatecheck).*`),
                (`flag name is not "equalsIgnoreCase"`)
              }
            }
          }
        }
      }
    },
    NOT {
      EXISTS (`data flow barrier node BARRIER`) {
        AND {
          (`BARRIER is in a callable`),
          (`the callable name matches regex pattern ^(?i)(_)*((no|ignore|disable)(strictssl|ssl|verify|verification|hostname)|(set)?(accept|trust|ignore|allow)(all|every|any)|(use|do|enable)insecure|(set|do|use)?no.*(check|validation|verify|verification)|disable).*$`)
        }
      }
    }
  }
}
